〇、IOC控制反转 把对象创建和对象之间的调用交给Spring进行管理，降低耦合度。
xml解析、工厂模式、反射。
一、Bean（使用xml） 1.0、使用Bean创建对象 1.0.0、准备对象 public class User {  private String name;  private int age;   public User(String name, int age) {  this.name = name;  this.age = age;  }   public String getName() {  return name;  }   public void setName(String name) {  this.name = name;  }   public User() {}   public int getAge() {  return age;  }   public void setAge(int age) {  this.age = age;  }   @Override  public String toString() {  return &#34;User{&#34; +  &#34;name=&#39;&#34; + name + &#39;\&#39;&#39; +  &#34;, age=&#34; + age +  &#39;}&#39;;  } } public class MainApplication {  public static void main(String[] args) {  ClassPathXmlApplicationContext classPathXmlApplicationContext = new ClassPathXmlApplicationContext(&#34;Bean.xml&#34;);  User user = (User) classPathXmlApplicationContext.getBean(&#34;user&#34;);  System.out.println(user);  } } 1.0.1、使用无参构造和setter方法 &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt;  &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;  &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt; &lt;/beans&gt; 1.0.2、使用有参构造方法 &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt;  &lt;constructor-arg name=&#34;name&#34; value=&#34;Jin&#34;/&gt;  &lt;!-- &lt;constructor-arg index=&#34;0&#34; value=&#34;Jin&#34;/&gt; --&gt;  &lt;constructor-arg name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt; &lt;/beans&gt; 1.0.3、使用p &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;  xmlns:p=&#34;http://www.springframework.org/schema/p&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34; p:name=&#34;Jin&#34; p:age=&#34;18&#34;/&gt; &lt;/beans&gt; 1.0.4、设置空值 &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt;  &lt;property name=&#34;name&#34;&gt;&lt;null/&gt;&lt;/property&gt;  &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt; &lt;/beans&gt; 1.1、注入 准备对象 public class UserService {  private User user;   public User getUser() {  return user;  }   public void setUser(User user) {  this.user = user;  }   @Override  public String toString() {  return &#34;UserService{&#34; +  &#34;user=&#34; + user +  &#39;}&#39;;  } } public class MainApplication {  public static void main(String[] args) {  ClassPathXmlApplicationContext classPathXmlApplicationContext = new ClassPathXmlApplicationContext(&#34;Bean.xml&#34;);  UserService userService = (UserService) classPathXmlApplicationContext.getBean(&#34;userService&#34;);  System.out.println(userService);  } } &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt;  &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;  &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt;  &lt;bean id=&#34;userService&#34; class=&#34;life.jinjiang.UserService&#34;&gt;  &lt;property name=&#34;user&#34; ref=&#34;user&#34;/&gt;  &lt;/bean&gt; &lt;/beans&gt; &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt; &lt;!-- &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;--&gt; &lt;!-- &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;--&gt;  &lt;/bean&gt;  &lt;bean id=&#34;userService&#34; class=&#34;life.jinjiang.UserService&#34;&gt;  &lt;property name=&#34;user&#34; ref=&#34;user&#34;/&gt;  &lt;property name=&#34;user.name&#34; value=&#34;Jin&#34;/&gt;  &lt;property name=&#34;user.age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt; &lt;/beans&gt; &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt; &lt;!-- &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;--&gt; &lt;!-- &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;--&gt;  &lt;/bean&gt;  &lt;bean id=&#34;userService&#34; class=&#34;life.jinjiang.UserService&#34;&gt;  &lt;property name=&#34;user&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt;  &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;  &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt;  &lt;/property&gt;  &lt;/bean&gt; &lt;/beans&gt; 1.2、作用域 单实例：singleton默认，读取配置文件时就创建
多实例：prototype，创建对象时才创建
public class MainApplication {  public static void main(String[] args) {  ClassPathXmlApplicationContext classPathXmlApplicationContext = new ClassPathXmlApplicationContext(&#34;Bean.xml&#34;);  User user = (User) classPathXmlApplicationContext.getBean(&#34;user&#34;);  User user2 = (User) classPathXmlApplicationContext.getBean(&#34;user&#34;);  System.out.println(user==user2);  } } 默认单实例输出true
更改配置文件
&lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34; scope=&#34;prototype&#34;&gt;  &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;  &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt; &lt;/beans&gt; 多实例输出false
1.3、生命周期 public class User {  private String name;  private int age;   public User(String name, int age) {  this.name = name;  this.age = age;  }   public String getName() {  return name;  }   public void setName(String name) {  this.name = name;  System.out.println(&#34;执行setter方法&#34;);  }   public User() {  System.out.println(&#34;执行构造方法&#34;);  }   public int getAge() {  return age;  }   public void setAge(int age) {  this.age = age;  }   @Override  public String toString() {  return &#34;User{&#34; +  &#34;name=&#39;&#34; + name + &#39;\&#39;&#39; +  &#34;, age=&#34; + age +  &#39;}&#39;;  }   public void initMethod() {  System.out.println(&#34;执行init方法&#34;);  }   public void destroyMethod() {  System.out.println(&#34;执行destroy方法&#34;);  } } public class MainApplication {  public static void main(String[] args) {  ClassPathXmlApplicationContext classPathXmlApplicationContext = new ClassPathXmlApplicationContext(&#34;Bean.xml&#34;);  User user = (User) classPathXmlApplicationContext.getBean(&#34;user&#34;);  classPathXmlApplicationContext.close();  } } 输出
执行构造方法 执行setter方法 执行init方法 执行destroy方法 后置处理器 public class MyBeanPost implements BeanPostProcessor {  @Override  public Object postProcessBeforeInitialization(Object bean, String beanName) throws BeansException {  System.out.println(&#34;执行postProcessBeforeInitialization方法&#34;);  return BeanPostProcessor.super.postProcessBeforeInitialization(bean, beanName);  }   @Override  public Object postProcessAfterInitialization(Object bean, String beanName) throws BeansException {  System.out.println(&#34;执行postProcessAfterInitialization方法&#34;);  return BeanPostProcessor.super.postProcessAfterInitialization(bean, beanName);  } } &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34; init-method=&#34;initMethod&#34; destroy-method=&#34;destroyMethod&#34;&gt;  &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;  &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt;  &lt;bean id=&#34;myBeanPost&#34; class=&#34;life.jinjiang.MyBeanPost&#34;/&gt; &lt;/beans&gt; 执行构造方法 执行setter方法 执行postProcessBeforeInitialization方法 执行init方法 执行postProcessAfterInitialization方法 执行destroy方法 1.4、自动装配 autowire属性有两种常用的值：ByName和ByType
ByName：根据对象名称来匹配
ByType：根据对象类型来匹配
public class User {  private String name;  private int age;   public User(String name, int age) {  this.name = name;  this.age = age;  }   public String getName() {  return name;  }   public void setName(String name) {  this.name = name;  }   public User() {}   public int getAge() {  return age;  }   public void setAge(int age) {  this.age = age;  }   @Override  public String toString() {  return &#34;User{&#34; +  &#34;name=&#39;&#34; + name + &#39;\&#39;&#39; +  &#34;, age=&#34; + age +  &#39;}&#39;;  } } public class UserService {  private User user;   public User getUser() {  return user;  }   public void setUser(User user) {  this.user = user;  }   @Override  public String toString() {  return &#34;UserService{&#34; +  &#34;user=&#34; + user +  &#39;}&#39;;  } } &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd&#34;&gt;  &lt;bean id=&#34;user&#34; class=&#34;life.jinjiang.User&#34;&gt;  &lt;property name=&#34;name&#34; value=&#34;Jin&#34;/&gt;  &lt;property name=&#34;age&#34; value=&#34;18&#34;/&gt;  &lt;/bean&gt;  &lt;bean id=&#34;userService&#34; class=&#34;life.jinjiang.UserService&#34; autowire=&#34;byName&#34;/&gt; &lt;/beans&gt; public class MainApplication {  public static void main(String[] args) {  ClassPathXmlApplicationContext classPathXmlApplicationContext = new ClassPathXmlApplicationContext(&#34;Bean.xml&#34;);  UserService userService = (UserService) classPathXmlApplicationContext.getBean(&#34;userService&#34;);  System.out.println(userService);  } } 二、Bean（使用注解） 2.0、使用Bean创建对象 注解有四种
@Component：
@Service：
@Controller：
@Repository：
功能都一样
&lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;beans xmlns=&#34;http://www.springframework.org/schema/beans&#34;  xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34;  xmlns:context=&#34;http://www.springframework.org/schema/context&#34;  xsi:schemaLocation=&#34;http://www.springframework.org/schema/beans http://www.springframework.org/schema/beans/spring-beans.xsd http://www.springframework.org/schema/context http://www.springframework.org/schema/context/spring-context.xsd&#34;&gt;  &lt;context:component-scan base-package=&#34;life.jinjiang&#34;/&gt; &lt;/beans&gt; import org.springframework.stereotype.Component;  @Component public class User {  private String name;  private int age;   public User(String name, int age) {  this.name = name;  this.age = age;  }   public String getName() {  return name;  }   public void setName(String name) {  this.name = name;  }   public User() {}   public int getAge() {  return age;  }   public void setAge(int age) {  this.age = age;  }   @Override  public String toString() {  return &#34;User{&#34; +  &#34;name=&#39;&#34; + name + &#39;\&#39;&#39; +  &#34;, age=&#34; + age +  &#39;}&#39;;  } } public class MainApplication {  public static void main(String[] args) {  ClassPathXmlApplicationContext classPathXmlApplicationContext = new ClassPathXmlApplicationContext(&#34;Bean.xml&#34;);  User user = (User) classPathXmlApplicationContext.getBean(&#34;user&#34;);  System.out.println(user);  } } 2.1、组件扫描配置 扫描life.jinjiang下的所有包和子包
&lt;context:component-scan base-package=&#34;life.jinjiang&#34;/&gt; 只扫描life.jinjiang下的@Component注解标注的类
&lt;context:component-scan base-package=&#34;life.jinjiang&#34; use-default-filters=&#34;false&#34;&gt;  &lt;context:include-filter type=&#34;annotation&#34; expression=&#34;org.springframework.stereotype.Component&#34;/&gt; &lt;/context:component-scan&gt; 扫描life.jinjiang下的除了@Controller下的包
&lt;context:component-scan base-package=&#34;life.jinjiang&#34;&gt;  &lt;context:exclude-filter type=&#34;annotation&#34; expression=&#34;org.springframework.stereotype.Controller&#34;/&gt; &lt;/context:component-scan&gt; 2.2、注入 2.2.0、@Autowired @Autowired根据类型自动注入
@Service public class UserService {  @Autowired  private User user;   public User getUser() {  return user;  }   public void setUser(User user) {  this.user = user;  }   @Override  public String toString() {  return &#34;UserService{&#34; +  &#34;user=&#34; + user +  &#39;}&#39;;  } } public class MainApplication {  public static void main(String[] args) {  ClassPathXmlApplicationContext classPathXmlApplicationContext = new ClassPathXmlApplicationContext(&#34;Bean.xml&#34;);  UserService userService = (UserService) classPathXmlApplicationContext.getBean(UserService.class);  System.out.println(userService);  } } 2.2.1、@Qualifier @Qualifier和@Autowired一起使用，根据属性名称自动注入
在下面情况中只使用@Autowired会出错，因为User的实现有两个类，应该明确具体的类。
public interface User {  void add(); } @Component public class UserImpl implements User {  private String name;  private int age;   public UserImpl(String name, int age) {  this.name = name;  this.age = age;  }   public String getName() {  return name;  }   public void setName(String name) {  this.name = name;  }   public UserImpl() {}   public int getAge() {  return age;  }   public void setAge(int age) {  this.age = age;  }   @Override  public String toString() {  return &#34;User{&#34; +  &#34;name=&#39;&#34; + name + &#39;\&#39;&#39; +  &#34;, age=&#34; + age +  &#39;}&#39;;  }    @Override  public void add() {  System.out.println(&#34;add&#34;);  } } @Component public class UserImpl2 implements User{  @Override  public void add() {  System.out.println(&#34;add&#34;);  } } @Service public class UserService {  @Autowired  private User user;   public User getUser() {  return user;  }   public void setUser(UserImpl user) {  this.user = user;  }   @Override  public String toString() {  return &#34;UserService{&#34; +  &#34;user=&#34; + user +  &#39;}&#39;;  } } nested exception is org.springframework.beans.factory.NoUniqueBeanDefinitionException: No qualifying bean of type &#39;life.jinjiang.User&#39; available: expected single matching bean but found 2: userImpl,userImpl2 在@Autowired下添加@Qualifier(&quot;userImpl&quot;)可指定userImpl类
@Service public class UserService {  @Autowired  @Qualifier(&#34;userImpl&#34;)  private User user;   public User getUser() {  return user;  }   public void setUser(UserImpl user) {  this.user = user;  }   @Override  public String toString() {  return &#34;UserService{&#34; +  &#34;user=&#34; + user +  &#39;}&#39;;  } } 2.2.2、@Value @Value可以注入值
@Value(&#34;Jin&#34;) private String name; @Value(&#34;18&#34;) private int age; 2.3、完全注解 不使用xml配置文件
创建一个配置类
@Configuration @ComponentScan(&#34;life.jinjiang&#34;) public class MyConfig { } public class MainApplication {  public static void main(String[] args) {  ApplicationContext applicationContext = new AnnotationConfigApplicationContext(MyConfig.class);  UserService userService = (UserService) applicationContext.getBean(UserService.class);  System.out.println(userService);  } }

JAVA内置注解 1、@Override注解 @Override注解在重写父类方法时使用。
@Override public String toString() {  return &#34;User{&#34; +  &#34;name=&#39;&#34; + name + &#39;\&#39;&#39; +  &#34;, id=&#34; + id +  &#39;}&#39;; } @Deprecated注解表示已弃用
@Deprecated public void eat() {  System.out.println(&#34;eating...&#34;); } @SuppressWarnings(&quot;all&quot;)表示忽略所有警告
@SuppressWarnings(&#34;all&#34;) public void eat() {  System.out.println(&#34;eating...&#34;); } 自定义注解和使用自定义注解 public @interface MyAnno {} @MyAnno public void eat() {  System.out.println(&#34;eating...&#34;); } 自定义注解的属性 注解的属性类型限制：基本数据类型、String、枚举、注解、和前面类型的数组。
enum Person {  P1, P2 }  public @interface MyAnno {  String name();  int age();  Person per();  MyAnno2 an();  String[] str(); }  @MyAnno(name=&#34;jin&#34;, age = 18, per = Person.P1, an = @MyAnno2, str = {&#34;aaa&#34;, &#34;bbb&#34;}) public void eat() {  System.out.println(&#34;eating...&#34;); } 注解可以使用默认值
public @interface MyAnno {  String name();  int age() default 18; }  @MyAnno(name=&#34;jin&#34;) public void eat() { System.out.println(&#34;eating...&#34;); } 如果属性只有一个value则可以省略
public @interface MyAnno {  String value(); }  @MyAnno(&#34;jin&#34;) public void eat() {  System.out.println(&#34;eating...&#34;); } 自定义注解的元注解 1、@Target元注解表示注解生效的位置 ElementType.TYPE在类上生效
ElementType.METHOD在方法上生效
ElementType.FIELD在成员变量上生效
@Target({ElementType.TYPE, ElementType.METHOD, ElementType.FIELD}) public @interface MyAnno {  String value(); } 2、@Retention元注解表示注解保留的阶段 RetentionPolicy.SOURCE源码阶段
RetentionPolicy.CLASS字节码阶段
RetentionPolicy.RUNTIME运行时阶段
3、@Documented元注解表示注解是否提取到API文档 4、@Inherited元注解表示注解是否被子类继承 解析注解 Target({ElementType.TYPE, ElementType.METHOD, ElementType.FIELD}) @Retention(RetentionPolicy.RUNTIME) public @interface MyAnno {  String className();  String methodName(); }   public static void run(Class&lt;MainApplication&gt; mainApplicationClass) throws Exception {  MyAnno annotation = mainApplicationClass.getAnnotation(MyAnno.class);  String className = annotation.className();  String methodName = annotation.methodName();  Class cls = Class.forName(className);  Constructor constructor = cls.getConstructor();  Object obj = constructor.newInstance();  Method method = cls.getMethod(methodName);  method.invoke(obj); }   @MyAnno(className = &#34;com.jin.learnjava.User&#34;, methodName = &#34;eat&#34;) public class MainApplication {  public static void main(String[] args) throws Exception {  Runner.run(MainApplication.class);  } }

